def battle_in_year(year):
    battles = {
        490: 'Battle of Marathon',
        480: ['Battle of Thermopylae', 'Battle of Salamis'],
        479: ['Battle of Plataea', 'Battle of Mycale']
    }
    return battles.get(year, None)


Example usage:
python
print(battle_in_year(479))  # Output: ['Battle of Plataea', 'Battle of Mycale']
print(battle_in_year(485))  # Output: None
